   317→// reloadHostEndpoint (re)attaches programs from bpf_host.c to cilium_host,
   318→// cilium_net and external (native) devices.
   319→func reloadHostEndpoint(cfg *datapath.LocalNodeConfiguration, ep datapath.Endpoint, spec *ebpf.CollectionSpec) error {
   320→	// Replace programs on cilium_host.
   321→	if err := attachCiliumHost(ep, spec); err != nil {
   322→		return fmt.Errorf("attaching cilium_host: %w", err)
   323→	}
   324→
   325→	if err := attachCiliumNet(cfg, ep, spec); err != nil {
   326→		return fmt.Errorf("attaching cilium_host: %w", err)
   327→	}
   328→
   329→	if err := attachNetworkDevices(cfg, ep, spec); err != nil {
   330→		return fmt.Errorf("attaching cilium_host: %w", err)
   331→	}
   332→
   333→	return nil
   334→}
